const GENERIC_HEADLINE = "Something went wrong";

const MAX_USER_BODY_CHARS = 500;
const MAX_JSON_USER_FIELD_CHARS = 280;

export type DescribeRouteErrorResult = {
  headline: string;
  userSummary: string | null;
  technicalDetails: string;
};

function getHttpStatus(error: unknown): number | undefined {
  if (error && typeof error === "object" && "status" in error) {
    const s = (error as { status: unknown }).status;
    if (typeof s === "number") {
      return s;
    }
  }
  return undefined;
}

function tryPrettyPrintJsonMessage(message: string): string {
  const t = message.trim();
  if (!t.startsWith("{") && !t.startsWith("[")) {
    return message;
  }
  try {
    return JSON.stringify(JSON.parse(t) as unknown, null, 2);
  } catch {
    return message;
  }
}

function formatErrorCause(cause: unknown, depth: number): string {
  if (depth <= 0 || cause === undefined || cause === null) {
    return "";
  }
  if (cause instanceof Error) {
    const block =
      cause.stack ??
      `${cause.name}: ${cause.message}`.trim() ||
      String(cause);
    const next =
      "cause" in cause
        ? formatErrorCause(
            (cause as Error & { cause?: unknown }).cause,
            depth - 1,
          )
        : "";
    return `\n\nCaused by: ${block}${next}`;
  }
  return `\n\nCaused by: ${String(cause)}`;
}

export function buildTechnicalDetails(error: unknown): string {
  if (!(error instanceof Error)) {
    return String(error);
  }

  const msgTech = tryPrettyPrintJsonMessage(error.message);
  let core: string;

  if (error.stack) {
    if (error.message && error.stack.includes(error.message)) {
      core = error.stack.replace(error.message, msgTech);
    } else if (!error.message) {
      core = error.stack;
    } else {
      core = `${msgTech}\n\n${error.stack}`;
    }
  } else {
    core = msgTech;
  }

  const cause =
    "cause" in error
      ? formatErrorCause(
          (error as Error & { cause?: unknown }).cause,
          3,
        )
      : "";
  return cause ? `${core}${cause}` : core;
}

function looksLikeStackTrace(s: string): boolean {
  if (!s.includes("\n")) {
    return false;
  }
  return /^\s*at\s+/m.test(s) || /at\s+[\w$.]+\s+\([^)]+\)/m.test(s);
}

function looksLikeHtml(s: string): boolean {
  return /^\s*<!doctype/i.test(s) || /<html[\s>]/i.test(s);
}

function isUnsafeUserMessage(s: string): boolean {
  return (
    s.length > MAX_USER_BODY_CHARS ||
    looksLikeStackTrace(s) ||
    looksLikeHtml(s)
  );
}

function extractJsonUserText(parsed: Record<string, unknown>): string | null {
  const keys = ["message", "detail", "title", "error"] as const;
  for (const k of keys) {
    const v = parsed[k];
    if (typeof v === "string" && v.trim()) {
      const t = v.trim();
      if (
        t.length <= MAX_JSON_USER_FIELD_CHARS &&
        !looksLikeStackTrace(t) &&
        !looksLikeHtml(t)
      ) {
        return t;
      }
    }
  }
  return null;
}

function statusToUserCopy(status: number): {
  headline: string;
  summary: string | null;
} {
  if (status === 403) {
    return {
      headline: "Access denied",
      summary: "You don't have permission to do that.",
    };
  }
  if (status === 404) {
    return {
      headline: "Not found",
      summary: "We couldn't find what you were looking for.",
    };
  }
  if (status === 409) {
    return {
      headline: "Conflict",
      summary:
        "This request conflicts with the current state. Try again or refresh the page.",
    };
  }
  if (status === 422) {
    return {
      headline: "Invalid request",
      summary:
        "Some of the information couldn't be processed. Check your input and try again.",
    };
  }
  if (status === 429) {
    return {
      headline: "Too many requests",
      summary: "Please wait a moment and try again.",
    };
  }
  if (status >= 500) {
    return {
      headline: "Something went wrong",
      summary:
        "We couldn't complete this request. Please try again in a few moments.",
    };
  }
  if (status >= 400) {
    return {
      headline: "Request failed",
      summary:
        "The request couldn't be completed. Try again or contact support if this continues.",
    };
  }
  return { headline: GENERIC_HEADLINE, summary: null };
}

function tryParseJsonUserMessage(message: string): string | null {
  const t = message.trim();
  if (!t.startsWith("{")) {
    return null;
  }
  try {
    const parsed = JSON.parse(t) as unknown;
    if (
      typeof parsed === "object" &&
      parsed !== null &&
      !Array.isArray(parsed)
    ) {
      return extractJsonUserText(parsed as Record<string, unknown>);
    }
  } catch {
    return null;
  }
  return null;
}

export function describeRouteError(error: unknown): DescribeRouteErrorResult {
  const technicalDetails = buildTechnicalDetails(error);

  if (!(error instanceof Error)) {
    const s = String(error);
    if (isUnsafeUserMessage(s)) {
      return {
        headline: GENERIC_HEADLINE,
        userSummary: null,
        technicalDetails,
      };
    }
    return {
      headline: GENERIC_HEADLINE,
      userSummary: s,
      technicalDetails,
    };
  }

  const message = error.message.trim();
  const status = getHttpStatus(error);

  if (status === 401) {
    return {
      headline: "Session expired",
      userSummary: "Please sign in again to continue.",
      technicalDetails,
    };
  }

  const jsonUser =
    message.startsWith("{") || message.startsWith("[")
      ? tryParseJsonUserMessage(message)
      : null;

  if (status !== undefined) {
    const mapped = statusToUserCopy(status);
    if (jsonUser) {
      return {
        headline: mapped.headline,
        userSummary: jsonUser,
        technicalDetails,
      };
    }
    return {
      headline: mapped.headline,
      userSummary: mapped.summary,
      technicalDetails,
    };
  }

  if (message && isUnsafeUserMessage(message)) {
    return {
      headline: GENERIC_HEADLINE,
      userSummary: null,
      technicalDetails,
    };
  }

  if (jsonUser) {
    return {
      headline: GENERIC_HEADLINE,
      userSummary: jsonUser,
      technicalDetails,
    };
  }

  if (message && !isUnsafeUserMessage(message)) {
    return {
      headline: GENERIC_HEADLINE,
      userSummary: message,
      technicalDetails,
    };
  }

  return {
    headline: GENERIC_HEADLINE,
    userSummary: null,
    technicalDetails,
  };
}

