import { useEffect, useRef } from "react";
import { describeRouteError } from "@/lib/describe-route-error";
import { logErrorToRollbar } from "@/lib/rollbar";
import type { ErrorComponentProps } from "@tanstack/react-router";
import { Link, useRouter } from "@tanstack/react-router";
import { Button, Card } from "@workspace/ui";
import { AlertCircle, Home, RefreshCw } from "lucide-react";

export function RootError({ error, reset }: ErrorComponentProps) {
  const router = useRouter();
  const { headline, userSummary, technicalDetails } =
    describeRouteError(error);
  const showTechnicalPanel = technicalDetails.length > 0;
  const loggedKeyRef = useRef<string | null>(null);

  useEffect(() => {
    const key =
      error instanceof Error
        ? `${error.message}\n${error.stack ?? ""}`
        : String(error);
    if (loggedKeyRef.current === key) {
      return;
    }
    loggedKeyRef.current = key;
    const err = error instanceof Error ? error : new Error(String(error));
    logErrorToRollbar(err, { source: "rootError" });
  }, [error]);

  const handleRetry = () => {
    void router.invalidate();
    reset();
  };

  return (
    <div className="relative flex min-h-screen flex-col items-center justify-center overflow-hidden bg-muted p-6 font-outfit">
      <div
        aria-hidden
        className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-destructive/5 via-transparent to-transparent"
      />
      <div
        aria-hidden
        className="pointer-events-none absolute inset-0 bg-[linear-gradient(to_right,oklch(0_0_0/0.03)_1px,transparent_1px),linear-gradient(to_bottom,oklch(0_0_0/0.03)_1px,transparent_1px)] bg-size-[24px_24px] opacity-[0.35]"
      />
      <Card
        className="relative w-full max-w-lg border-border/80 p-8 shadow-md"
        data-testid="root-error"
      >
        <div className="flex flex-col items-center text-center" role="alert">
          <div className="mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-destructive/10 text-destructive ring-1 ring-destructive/15">
            <AlertCircle aria-hidden className="h-6 w-6" />
          </div>
          <h1 className="font-bold text-foreground text-xl tracking-tight">
            {headline}
          </h1>
          {userSummary ? (
            <p className="mt-3 max-w-md whitespace-pre-wrap text-muted-foreground text-sm leading-relaxed">
              {userSummary}
            </p>
          ) : (
            <p className="mt-3 text-muted-foreground text-sm leading-relaxed">
              An unexpected error occurred. You can try again or return home.
            </p>
          )}
        </div>

        <div className="mt-8 flex flex-col gap-2 sm:flex-row sm:justify-center">
          <Button
            className="gap-2"
            type="button"
            variant="default"
            onClick={handleRetry}
          >
            <RefreshCw className="h-4 w-4" />
            Try again
          </Button>
          <Button asChild className="gap-2" type="button" variant="outline">
            <Link to="/">
              <Home className="h-4 w-4" />
              Go home
            </Link>
          </Button>
        </div>

        {showTechnicalPanel ? (
          <details className="mt-8 rounded-lg border border-border bg-card/50 text-left">
            <summary className="cursor-pointer px-3 py-2 font-medium text-muted-foreground text-xs uppercase tracking-wide">
              Technical details
              {import.meta.env.DEV ? (
                <span className="ml-2 font-normal normal-case text-[10px] text-muted-foreground/80">
                  (development)
                </span>
              ) : null}
            </summary>
            <pre className="max-h-48 overflow-auto whitespace-pre-wrap break-words border-border border-t p-3 font-mono text-[11px] text-muted-foreground leading-relaxed">
              {technicalDetails}
            </pre>
          </details>
        ) : null}
      </Card>
    </div>
  );
}

import { describe, expect, it } from "vitest";
import { OrgApiError } from "@/server/error";
import {
  buildTechnicalDetails,
  describeRouteError,
} from "./describe-route-error";

describe("describeRouteError", () => {
  it("maps 401 to session copy", () => {
    const r = describeRouteError(new OrgApiError("unauthorized", 401));
    expect(r.headline).toBe("Session expired");
    expect(r.userSummary).toBe("Please sign in again to continue.");
    expect(r.technicalDetails).toContain("unauthorized");
  });

  it("maps 500 with plain body to calm 5xx copy, not raw body in summary", () => {
    const r = describeRouteError(
      new OrgApiError("Internal Server Error", 500),
    );
    expect(r.headline).toBe("Something went wrong");
    expect(r.userSummary).toBe(
      "We couldn't complete this request. Please try again in a few moments.",
    );
    expect(r.userSummary).not.toContain("Internal Server Error");
    expect(r.technicalDetails).toContain("Internal Server Error");
  });

  it("uses JSON message/detail for user summary when status is present", () => {
    const body = JSON.stringify({
      detail: "Email is already registered",
      errors: { email: ["taken"] },
    });
    const r = describeRouteError(new OrgApiError(body, 422));
    expect(r.headline).toBe("Invalid request");
    expect(r.userSummary).toBe("Email is already registered");
    expect(r.userSummary).not.toContain("email");
    expect(r.technicalDetails).toContain("Email is already registered");
  });

  it("does not put stack-like message in user summary when status is absent", () => {
    const stackMsg = `Something failed
    at foo (bar.tsx:1:1)
    at baz (qux.tsx:2:2)`;
    const err = new Error(stackMsg);
    const r = describeRouteError(err);
    expect(r.userSummary).toBeNull();
    expect(r.technicalDetails).toContain("at foo");
  });

  it("formats technical details with stack", () => {
    const err = new Error("boom");
    err.stack = `Error: boom
  at test (file.ts:1:1)`;
    const r = describeRouteError(err);
    expect(r.userSummary).toBe("boom");
    expect(r.technicalDetails).toContain("boom");
    expect(r.technicalDetails).toContain("at test");
  });

  it("handles non-Error throws", () => {
    const r = describeRouteError("plain string");
    expect(r.headline).toBe("Something went wrong");
    expect(r.userSummary).toBe("plain string");
    expect(r.technicalDetails).toBe("plain string");
  });

  it("maps 404 with JSON message field", () => {
    const body = JSON.stringify({ message: "Resource missing" });
    const r = describeRouteError(new OrgApiError(body, 404));
    expect(r.headline).toBe("Not found");
    expect(r.userSummary).toBe("Resource missing");
  });
});

describe("buildTechnicalDetails", () => {
  it("pretty-prints JSON message in technical output", () => {
    const json = '{"a":1,"b":2}';
    const err = new OrgApiError(json, 500);
    const t = buildTechnicalDetails(err);
    expect(t).toContain('"a": 1');
    expect(t).toContain('"b": 2');
  });
});
